class LRUCache:
    def __init__(self, capacity: int):
        self.cap = capacity
        self.cache = {}
        self.nodes = []
    def get(self, key: int) -> int:
        if key in self.cache:
            self.nodes.remove(key)
            self.nodes.append(key)
            return self.cache[key]
        return -1
    def put(self, key: int, value: int) -> None:
        if key in self.cache:
            self.nodes.remove(key)
        self.cache[key] = value
        self.nodes.append(key)
        if len(self.nodes) > self.cap:
            lru = self.nodes.pop(0)
            del self.cache[lru]

def solve(commands):
    lines = commands.strip().split('\n')
    capacity = int(lines[0])
    obj = LRUCache(capacity)
    results = []
    for line in lines[1:]:
        parts = line.split()
        cmd = parts[0]
        if cmd == 'put':
            obj.put(int(parts[1]), int(parts[2]))
            results.append('null')
        elif cmd == 'get':
            results.append(str(obj.get(int(parts[1]))))
    return ' '.join(results)

